    def test_resume_reopens_terminalized_orchestration_run_row(self) -> None:
        """Resuming a terminal orchestration must re-open its agent_runs row to
        `running` (clearing finished_at), symmetric with the meta.status reset,
        so a live resumed run never carries a stale terminal row that
        validate_workspace_root would age out as cleanup-pending (P1 resume)."""
        with tempfile.TemporaryDirectory() as tmp:
            repo_root = Path(tmp)
            oid = "orch_resume_reopen_001"
            init_orchestration(repo_root=repo_root, orchestration_id=oid)
            root = repo_root / "workspace" / "orchestrations" / oid
            orch_arid = json.loads(
                (root / "orchestration_meta.json").read_text(encoding="utf-8")
            )["orchestration_agent_run_id"]

            def _orch_row() -> dict:
                for line in (root / "agent_runs.jsonl").read_text().splitlines():
                    if line.strip() and json.loads(line).get("agent_run_id") == orch_arid:
                        return json.loads(line)
                raise AssertionError("orchestration row missing")

            def _session_orch_status() -> str:
                doc = json.loads(
                    (root / "session_run_index.json").read_text(encoding="utf-8")
                )
                return next(
                    e for e in doc["entries"] if e["agent_run_id"] == orch_arid
                )["status"]

            # First run terminalizes the row.
            update_orchestration_status(
                repo_root=repo_root,
                orchestration_id=oid,
                status="fail_closed",
                reason_code="sandbox_enforcement_violation",
                reason_detail="first run",
            )
            self.assertEqual(_orch_row()["status"], "fail_closed")
            self.assertIn("finished_at", _orch_row())
            self.assertEqual(_session_orch_status(), "fail_closed")

            # Resume must re-open the row to running and drop finished_at.
            enable_checkpoint_resume(repo_root, oid)
            reopened = _orch_row()
            self.assertEqual(reopened["status"], "running")
            self.assertNotIn("finished_at", reopened)
            # session_run_index orchestration row is reset symmetrically.
            self.assertEqual(_session_orch_status(), "running")

            # The resumed run can re-terminalize it fresh (forward transition).
            update_orchestration_status(
                repo_root=repo_root,
                orchestration_id=oid,
                status="fail_closed",
                reason_code="sandbox_enforcement_violation",
                reason_detail="resumed run",
            )
            self.assertEqual(_orch_row()["status"], "fail_closed")
            self.assertIn("finished_at", _orch_row())
            self.assertEqual(_session_orch_status(), "fail_closed")

    def test_resume_clears_stale_active_child_markers(self) -> None:
        """A host that died mid-launch leaves the active_child window open. Resuming
        a TERMINAL orchestration must clear `active_child_agent_run_id.txt` and the
        per-arid `active_children/<arid>.txt` markers, else the resumed agent's first
        Claude record-launch hits the sequential-child check and recovery is wedged
        (Codex P1: launch_incomplete_active_child recovery)."""
        with tempfile.TemporaryDirectory() as tmp:
            repo_root = Path(tmp)
            oid = "orch_resume_active_child"
            init_orchestration(repo_root=repo_root, orchestration_id=oid)
            root = repo_root / "workspace" / "orchestrations" / oid
            child = "f00d83b5-bfbf-4c0b-8e78-95da6bf6ba5e"
            (root / "active_child_agent_run_id.txt").write_text(child, encoding="utf-8")
            markers = root / "active_children"
            markers.mkdir(exist_ok=True)
            (markers / f"{child}.txt").write_text(child, encoding="utf-8")

            # Terminalize (a dangling launch is terminalized to fail by run_workflow).
            update_orchestration_status(
                repo_root=repo_root,
                orchestration_id=oid,
                status="fail",
                reason_code="launch_incomplete_active_child",
                reason_detail="child launch did not return",
            )

            enable_checkpoint_resume(repo_root, oid)

            self.assertFalse((root / "active_child_agent_run_id.txt").exists())
            self.assertFalse((markers / f"{child}.txt").exists())
            log_events = [
                json.loads(line)
                for line in (root / "phase_state_log.jsonl").read_text().splitlines()
                if line.strip()
            ]
            cleared = [e for e in log_events if e.get("event") == "resume_cleared_stale_active_child"]
            self.assertEqual(len(cleared), 1)
            self.assertEqual(cleared[0].get("cleared_active_child_arids"), [child])

    def test_resume_prunes_orphan_agent_graph_edge(self) -> None:
        """The abandoned child's agent_graph edge (written by record_launch before the
        marker) has no terminal agent_runs row. Resuming a TERMINAL orchestration must
        prune that orphan edge, else the resumed run's set-status pass is rejected by
        _validate_orchestration_completion_for_pass (Codex P1). A valid edge whose child
        has a run row must be kept."""
        with tempfile.TemporaryDirectory() as tmp:
            repo_root = Path(tmp)
            oid = "orch_resume_orphan_edge"
            init_orchestration(repo_root=repo_root, orchestration_id=oid)
            root = repo_root / "workspace" / "orchestrations" / oid
            orch_arid = json.loads(
                (root / "orchestration_meta.json").read_text(encoding="utf-8")
            )["orchestration_agent_run_id"]
            good_child = "good-child-arid"
            dangling = "f00d83b5-dangling"
            # The dangling child was genuinely launched (record_launch wrote its
            # launches/<arid>.request.json) — the scope signal for pruning.
            (root / "launches").mkdir(exist_ok=True)
            (root / "launches" / f"{dangling}.request.json").write_text("{}", encoding="utf-8")
            # A real terminal run only for the good child.
            with (root / "agent_runs.jsonl").open("a", encoding="utf-8") as f:
                f.write(
                    json.dumps(
                        {"agent_run_id": good_child, "agent_role": "substep",
                         "status": "pass", "finished_at": "2026-06-16T12:40:00Z"}
                    )
                    + "\n"
                )
            (root / "agent_graph.json").write_text(
                json.dumps(
                    {
                        "edges": [
                            {"parent_agent_run_id": orch_arid, "child_agent_run_id": good_child,
                             "relation_type": "launch"},
                            {"parent_agent_run_id": orch_arid, "child_agent_run_id": dangling,
                             "relation_type": "launch"},
                        ]
                    }
                ),
                encoding="utf-8",
            )

            update_orchestration_status(
                repo_root=repo_root,
                orchestration_id=oid,
                status="fail",
                reason_code="launch_incomplete_active_child",
                reason_detail="child launch did not return",
            )
            enable_checkpoint_resume(repo_root, oid)

            edges = json.loads((root / "agent_graph.json").read_text(encoding="utf-8"))["edges"]
            children = [e["child_agent_run_id"] for e in edges]
            self.assertIn(good_child, children)
            self.assertNotIn(dangling, children)
            log_events = [
                json.loads(line)
                for line in (root / "phase_state_log.jsonl").read_text().splitlines()
                if line.strip()
            ]
            pruned = [e for e in log_events if e.get("event") == "resume_pruned_orphan_graph_edges"]
            self.assertEqual(len(pruned), 1)
            self.assertEqual(pruned[0].get("pruned_child_agent_run_ids"), [dangling])

    def test_resume_tombstones_orphan_launch_artifacts(self) -> None:
        """Resume writes launches/<arid>.pruned.json for the abandoned launch so a
        later inspection can distinguish the residual orphan artifacts (no terminal
        agent_runs row, no child_returns ack) from a real protocol violation."""
        with tempfile.TemporaryDirectory() as tmp:
            repo_root = Path(tmp)
            oid = "orch_resume_tombstone"
            init_orchestration(repo_root=repo_root, orchestration_id=oid)
            root = repo_root / "workspace" / "orchestrations" / oid
            orch_arid = json.loads(
                (root / "orchestration_meta.json").read_text(encoding="utf-8")
            )["orchestration_agent_run_id"]
            dangling = "dead-air-dangling-arid"
            (root / "launches").mkdir(exist_ok=True)
            (root / "launches" / f"{dangling}.request.json").write_text("{}", encoding="utf-8")
            (root / "agent_graph.json").write_text(
                json.dumps(
                    {
                        "edges": [
                            {"parent_agent_run_id": orch_arid, "child_agent_run_id": dangling,
                             "relation_type": "launch"},
                        ]
                    }
                ),
                encoding="utf-8",
            )

            update_orchestration_status(
                repo_root=repo_root,
                orchestration_id=oid,
                status="fail",
                reason_code="launch_incomplete_active_child",
                reason_detail="child launch did not return",
            )
            enable_checkpoint_resume(repo_root, oid)

            tomb = root / "launches" / f"{dangling}.pruned.json"
            self.assertTrue(tomb.is_file())
            doc = json.loads(tomb.read_text(encoding="utf-8"))
            self.assertEqual(doc["agent_run_id"], dangling)
            self.assertEqual(doc["reason"], "resume_pruned_orphan")
            log_events = [
                json.loads(line)
                for line in (root / "phase_state_log.jsonl").read_text().splitlines()
                if line.strip()
            ]
            tombstoned = [
                e for e in log_events if e.get("event") == "resume_tombstoned_orphan_launches"
            ]
            self.assertEqual(len(tombstoned), 1)
            self.assertIn(dangling, tombstoned[0].get("tombstoned_agent_run_ids"))

    def test_resume_does_not_tombstone_returned_or_invalid_children(self) -> None:
        """A cleared active-child marker is NOT a sufficient orphan signal: a child
        that returned (child_returns ack) or attempted terminalization
        (agent_runs_invalid entry) must NOT be tombstoned as an expected orphan — only
        the genuinely-abandoned launch is."""
        with tempfile.TemporaryDirectory() as tmp:
            repo_root = Path(tmp)
            oid = "orch_resume_tombstone_protected"
            init_orchestration(repo_root=repo_root, orchestration_id=oid)
            root = repo_root / "workspace" / "orchestrations" / oid
            (root / "launches").mkdir(exist_ok=True)
            (root / "child_returns").mkdir(exist_ok=True)
            (root / "active_children").mkdir(exist_ok=True)

            dangling = "genuine-orphan-arid"
            returned = "returned-but-no-row-arid"
            invalid = "invalid-run-arid"
            for arid in (dangling, returned, invalid):
                (root / "launches" / f"{arid}.request.json").write_text("{}", encoding="utf-8")
                # All three left a stale active_children marker (host died mid-flight).
                (root / "active_children" / f"{arid}.txt").write_text(arid, encoding="utf-8")
            # `returned` has a child_returns ack; `invalid` has an invalid-run entry.
            (root / "child_returns" / f"{returned}.txt").write_text("ack", encoding="utf-8")
            (root / "agent_runs_invalid.jsonl").write_text(
                json.dumps({"agent_run_id": invalid, "agent_role": "substep"}) + "\n",
                encoding="utf-8",
            )

            update_orchestration_status(
                repo_root=repo_root,
                orchestration_id=oid,
                status="fail",
                reason_code="launch_incomplete_active_child",
                reason_detail="child launch did not return",
            )
            enable_checkpoint_resume(repo_root, oid)

            self.assertTrue((root / "launches" / f"{dangling}.pruned.json").is_file())
            self.assertFalse((root / "launches" / f"{returned}.pruned.json").is_file())
            self.assertFalse((root / "launches" / f"{invalid}.pruned.json").is_file())
            log_events = [
                json.loads(line)
                for line in (root / "phase_state_log.jsonl").read_text().splitlines()
                if line.strip()
            ]
            tombstoned = next(
                e for e in log_events if e.get("event") == "resume_tombstoned_orphan_launches"
            )
            self.assertEqual(tombstoned.get("tombstoned_agent_run_ids"), [dangling])

