    def test_record_agent_run_normalizes_backend_to_lowercase(self) -> None:
        """An agent_backend with mixed case and surrounding spaces is normalized to lowercase and trimmed."""
        cases = [
            ("Claude", "claude"),
            ("  Claude  ", "claude"),
            ("CODEX", "codex"),
        ]
        for idx, (raw, expected) in enumerate(cases):
            with self.subTest(raw=raw):
                with tempfile.TemporaryDirectory() as tmp:
                    repo_root = Path(tmp)
                    init_orchestration(repo_root=repo_root, orchestration_id="orch_001")
                    _mark_dependencies_ready(repo_root)
                    payload = record_agent_run(
                        repo_root=repo_root,
                        orchestration_id="orch_001",
                        payload={
                            "agent_run_id": f"orch_run_{idx:03d}",
                            "agent_role": "orchestration",
                            "status": "running",
                            "agent_backend": raw,
                        },
                    )
                    self.assertEqual(payload["agent_backend"], expected)


