class RecordTimeoutTests(unittest.TestCase):
    """Fix 5: record-timeout is the canonical recovery for child Agent stream timeouts."""

    def _setup_substep_launch(self, repo_root: Path) -> str:
        """Initialise an orchestration with a substep launched and return the substep agent_run_id."""
        init_orchestration(
            repo_root=repo_root,
            orchestration_id="orch_to_001",
            spec_ref="spec/problem/shallow_water2d/controlled_spec.md",
            source_dependency_ref="spec/problem/shallow_water2d/deps.yaml",
        )
        _mark_dependencies_ready(repo_root, "orch_to_001")
        write_preflight(
            repo_root=repo_root,
            orchestration_id="orch_to_001",
            payload={
                "status": "pass",
                "backend": "claude",
                "sandbox_runtime": "bwrap",
                "sandbox_enforced": True,
                "can_launch_step_agents": True,
                "can_launch_substep_agents": True,
                "feature_states": {"multi_agent": True, "hooks": True},
                "checks": [
                    {"name": "multi_agent_enabled", "pass": True},
                    {"name": "hooks_enabled", "pass": True},
                    {"name": "codex_home_writable", "pass": True},
                    {"name": "sandbox_bwrap_available", "pass": True},
                    {"name": "sandbox_bwrap_userns", "pass": True},
                ],
            },
        )
        substep_arid = "substep_run_to_001"
        record_launch(
            repo_root=repo_root,
            orchestration_id="orch_to_001",
            parent_agent_run_id="orch_run_to_001",
            child_agent_run_id=substep_arid,
            request_payload={
                "agent_model": "claude-opus-4-8",
                "agent_run_id": substep_arid,
                "agent_role": "substep",
                "node_key": "problem/shallow_water2d@0.3.0",
                "step": "generate",
                "substep": "generate",
                "source_id": "src_20260509_001",
                "orchestration_id": "orch_to_001",
                "parent_agent_run_id": "orch_run_to_001",
                "ir_ref": _FIX_IR_REF,
                "pipeline_ref": _FIX_PIPE_REF,
                "dependency_ref": _FIX_IR_REF,
                "skill_name": "workflow-generate-generate",
                "skill_ref": "skills/workflow-generate-generate/SKILL.md",
                "skill_must_read_refs": _fixture_skill_must_read_refs_substep(
                    "generate", "generate"
                ),
                "allowed_output_paths": [
                    f"{_FIX_PIPE_REF}/source/src_20260509_001/source_meta.json",
                ],
                "launch_prompt_full": render_launch_prompt_text({
                    "node_key": "problem/shallow_water2d@0.3.0",
                    "step": "generate",
                    "substep": "generate",
                    "agent_run_id": substep_arid,
                    "orchestration_id": "orch_to_001",
                    "parent_agent_run_id": "orch_run_to_001",
                    "workflow_mode": "dev",
                    "ir_ref": _FIX_IR_REF,
                    "pipeline_ref": _FIX_PIPE_REF,
                    "dependency_ref": _FIX_IR_REF,
                    "skill_name": "workflow-generate-generate",
                    "skill_ref": "skills/workflow-generate-generate/SKILL.md",
                    "skill_must_read_refs": _fixture_skill_must_read_refs_substep(
                        "generate", "generate"
                    ),
                    "issue_severity": "none",
                    "repair_strategy": "none",
                    "repair_target_agent_run_id": "none",
                    "repair_reason": "none",
                }),
            },
            response_payload={
                "agent_run_id": substep_arid,
                "backend": "claude",
                "started_at": "2026-05-09T08:00:00Z",
                **_spawn_response_payload(substep_arid),
            },
        )
        return substep_arid

    def _deactivate(self, repo_root: Path, arid: str) -> None:
        """Helper: record child return ack (Adv-20/Adv-30) and clear the
        active marker so Adv-14 guard accepts the subsequent record-timeout
        call. Reads the per-arid parent_return_token issued by record-launch."""
        from tools.orchestration_runtime import (
            record_child_return, deactivate_child_agent,
            _parent_return_token_path,
        )
        token = _parent_return_token_path(
            repo_root, "orch_to_001", arid
        ).read_text(encoding="utf-8").strip()
        record_child_return(
            repo_root=repo_root,
            orchestration_id="orch_to_001",
            agent_run_id=arid,
            return_token=token,
        )
        deactivate_child_agent(
            repo_root=repo_root,
            orchestration_id="orch_to_001",
            child_run_id=arid,
        )

    def test_finalize_child_runs_full_sequence_in_one_call(self) -> None:
        from tools.orchestration_runtime import finalize_child, _parent_return_token_path
        with tempfile.TemporaryDirectory() as tmp:
            repo_root = Path(tmp)
            arid = self._setup_substep_launch(repo_root)
            token = _parent_return_token_path(
                repo_root, "orch_to_001", arid
            ).read_text(encoding="utf-8").strip()
            reply = (
                "status: fail\noutput_refs:\n- (none)\n"
                "rationale: generate fail-stopped (test fixture)"
            )
            result = finalize_child(
                repo_root=repo_root,
                orchestration_id="orch_to_001",
                agent_run_id=arid,
                return_token=token,
                reply_text=reply,
                agent_run_payload={
                    "agent_run_id": arid,
                    "agent_role": "substep",
                    "agent_backend": "claude",
                    "status": "fail",
                    "agent_session_id": arid,
                    "context_id": "ctx_finalize_001",
                    "context_isolated": True,
                    "node_key": "problem/shallow_water2d@0.3.0",
                    "started_at": "2026-05-09T08:00:00Z",
                    "finished_at": "2026-05-09T08:05:00Z",
                    "result_summary": "generate fail-stopped (test fixture)",
                },
            )
            self.assertEqual(result["status"], "fail")
            self.assertEqual(result["deactivated_child_run_id"], arid)
            self.assertNotIn("reply_over_budget", result)  # short reply is under budget
            # record-agent-run ran: terminal entry present.
            runs_path = repo_root / "workspace/orchestrations/orch_to_001/agent_runs.jsonl"
            entries = [json.loads(l) for l in runs_path.read_text().splitlines() if l.strip()]
            self.assertTrue(
                any(e.get("agent_run_id") == arid and e.get("status") == "fail" for e in entries)
            )
            # record-reply ran: reply.txt holds the verbatim reply.
            reply_path = (
                repo_root / "workspace/orchestrations/orch_to_001/launches" / f"{arid}.reply.txt"
            )
            self.assertEqual(reply_path.read_text(encoding="utf-8").rstrip("\n"), reply)
            # deactivate-child ran: the parent_return_token sidecar is consumed.
            self.assertFalse(
                _parent_return_token_path(repo_root, "orch_to_001", arid).exists()
            )

    def test_finalize_child_persists_best_effort_child_usage(self) -> None:
        # The finalize path embeds a best-effort `usage` field into the
        # agent_runs.jsonl entry so child token cost is durable in-repo. With no
        # ~/.claude transcript present (test env), it degrades to a status marker
        # rather than breaking finalization.
        from tools.orchestration_runtime import finalize_child, _parent_return_token_path
